#!/usr/bin/env node
/**
 * sample-daily — generated by JavisSkills/skill-creator
 * Triggered by openclaw cron OR by the LLM on user-typed commands.
 *
 * Usage:
 *   node sample-daily.js <userId>
 *   node sample-daily.js --help
 */
'use strict';

const fs = require('fs');
const path = require('path');
const { sanitizeId, safeUserPath, readJson, writeJson } = require('./data');

if (process.argv.includes('--help')) {
  console.log('Usage: node sample-daily.js <userId>');
  process.exit(0);
}

const userId = sanitizeId(process.argv[2]);

async function main() {
  const userState = fs.existsSync(safeUserPath(userId))
    ? readJson(safeUserPath(userId))
    : {};
  const output = JSON.stringify(userState, null, 2);
  console.log(output);
}

main().catch((err) => {
  console.error('❌', err.message);
  process.exit(1);
});
